/**
 * Repository Invalidation Methods
 * Cache invalidation methods for repository operations
 */
import type { IBaseRepository } from '../IBaseRepository';
/**
 * Invalidate all queries for this resource
 *
 * @param repository - Repository instance
 */
export declare function invalidateAll<TData>(repository: IBaseRepository<TData, unknown, unknown>): Promise<void>;
/**
 * Invalidate list queries
 *
 * @param repository - Repository instance
 */
export declare function invalidateLists<TData>(repository: IBaseRepository<TData, unknown, unknown>): Promise<void>;
/**
 * Invalidate detail query
 *
 * @param repository - Repository instance
 * @param id - Item ID
 */
export declare function invalidateDetail<TData>(repository: IBaseRepository<TData, unknown, unknown>, id: string | number): Promise<void>;
/**
 * Set query data (optimistic update)
 *
 * @param repository - Repository instance
 * @param id - Item ID
 * @param data - Data to set
 */
export declare function setData<TData>(repository: IBaseRepository<TData, unknown, unknown>, id: string | number, data: TData): void;
/**
 * Get query data from cache
 *
 * @param repository - Repository instance
 * @param id - Item ID
 * @returns Cached data or undefined
 */
export declare function getData<TData>(repository: IBaseRepository<TData, unknown, unknown>, id: string | number): TData | undefined;
/**
 * Remove query data from cache
 *
 * @param repository - Repository instance
 * @param id - Item ID
 */
export declare function clearData<TData>(repository: IBaseRepository<TData, unknown, unknown>, id: string | number): void;
